import './App.css';
import Header from './components/Header';
import React, { Component } from 'react';

export default class App extends Component {
  state = {
    title : "Pokédex",
    pokemons : [],
    isLoaded: false
  }
  componentDidMount(){
    //appel de l'api pokemon
    const nbPokemon = 151;
    fetch("https://pokeapi.co/api/v2/pokemon/1")
      .then(res => res.json())
      .then(
        (result) => {
          console.log(result)
          this.setState({
            isLoaded: true,
            pokemons: result
          });
        },
        (error) => {
          this.setState({
            isLoaded: true,
            error
          });
        }
      )

  }
  render() {
    return (
      <div className="App">
        <Header titre={this.state.title} />
        <section style={{width:"100%", height:"90vh", backgroundColor: 'lightgrey'}}>
          <ul>
          {/* {
            this.state.pokemons.map((val, key) =>{
              return (
              <li>
                <span>{val.name}</span>
                <img src="https://raw.githubusercontent.com/PokeAPI/sprites/master/sprites/pokemon/back/1.png"></img>
              </li>)
            })
          } */}
          </ul>
        </section>
      </div>
    )
  }
}
